function(config){
  const pageUrl = String((config&&config.page&&config.page.url)||location.href);
  const minItems = (config&&typeof config.minItems==='number')?config.minItems:5;
  const maxItems = 50;
  const target = (config&&config.target)||null;
  const searchQ = String((config&&(config.query||config.searchQuery))||'').trim();

  const norm=s=>String(s||'').replace(/\s+/g,' ').trim();
  const abs=href=>{href=String(href||'').trim(); if(!href) return ''; try{return new URL(href, location.href).href;}catch(e){return ''}};
  const txt=el=>norm(el?(el.innerText||el.textContent||''):'');
  const isBadText=t=>{t=(t||'').toLowerCase(); return /\b(sign in|log in|login|register|sign up|privacy|terms|help|feedback|settings|advert|sponsored)\b/.test(t)};
  const isInBadRegion=el=>{for(let n=el;n&&n.nodeType===1;n=n.parentElement){const tag=(n.tagName||'').toLowerCase(); if(tag==='header'||tag==='nav'||tag==='footer'||tag==='aside') return true; const id=(n.id||'').toLowerCase(); const cls=(n.className||'').toLowerCase(); if(/\b(rhs|right|sidebar|sidenav|nav|footer|header|cookie|consent|login|signup|modal|drawer)\b/.test(id+' '+cls)) return true;} return false;};
  const isResultLikeUrl=u=>{u=String(u||''); if(!u) return false; if(u.startsWith('javascript:')||u.startsWith('#')) return false; if(/\/search\?/.test(u) && /[?&](tbm|udm)=/.test(u)) return false; if(/\/policies\b|\/preferences\b/.test(u)) return false; return true;};

  function getScope(){
    if(target){
      if(target.by==='selector' && target.selector){const el=document.querySelector(target.selector); if(el) return el;}
      if(target.by==='query' && target.query){const el=document.querySelector(target.query); if(el) return el;}
      if(target.selector){const el=document.querySelector(target.selector); if(el) return el;}
      if(target.query){const el=document.querySelector(target.query); if(el) return el;}
    }
    const g=document.querySelector('#rso');
    if(g) return g;
    const main=document.querySelector('main')||document.querySelector('[role="main"]')||document.querySelector('#main')||document.body;
    return main||document.body;
  }

  function pickItems(items){
    if(!target||target.pick===undefined||target.pick===null) return items;
    const p=target.pick;
    if(typeof p==='number'){
      if(p===-1) return items.length?[items[items.length-1]]:[];
      const idx=p-1; return (idx>=0&&idx<items.length)?[items[idx]]:[];
    }
    if(typeof p==='string' && p.trim()){
      const needle=p.trim().toLowerCase();
      for(const it of items){
        const hay=(it.title+' '+it.summary+' '+it.url).toLowerCase();
        if(hay.indexOf(needle)!==-1) return [it];
      }
      return [];
    }
    return items;
  }

  function applyFilterSort(items){
    const f=(config&&config.filter)||null;
    if(f){
      if(typeof f==='function') items=items.filter(it=>{try{return !!f(it);}catch(e){return true;}});
      else if(typeof f==='string' && f.trim()){
        const needle=f.trim().toLowerCase();
        items=items.filter(it=>(it.title+' '+it.summary+' '+it.url).toLowerCase().indexOf(needle)!==-1);
      }
    }
    const s=(config&&config.sort)||null;
    if(s){
      if(typeof s==='function') items=items.slice().sort((a,b)=>{try{return s(a,b)||0;}catch(e){return 0;}});
      else if(typeof s==='string'){
        const key=s; items=items.slice().sort((a,b)=>String(a[key]||'').localeCompare(String(b[key]||'')));
      }
    }
    return items;
  }

  function extractFromContainer(container, strategy){
    const items=[];
    const seen=new Set();

    let nodes=[];
    if(strategy===1){
      nodes=Array.from(container.querySelectorAll(':scope > .MjjYud, :scope .MjjYud'));
      nodes=nodes.filter(n=>!isInBadRegion(n));
    }else{
      nodes=Array.from(container.querySelectorAll('article, [role="article"], li, .g, .MjjYud, .result, .card'));
      nodes=nodes.filter(n=>!isInBadRegion(n));
    }

    function isGoogleOrganic(node){
      if(!node) return false;
      if(node.querySelector('.yuRUbf a[href]') && node.querySelector('h3')) return true;
      if(node.querySelector('a[href] h3')) return true;
      return false;
    }

    const candidates=[];
    for(const n of nodes){
      if(!n || n.nodeType!==1) continue;
      if(strategy===1 && !isGoogleOrganic(n)) continue;
      if(n.querySelector('[aria-label="Ads"], [data-text-ad], .uEierd, .commercial-unit-desktop-top, .ads-ad')) continue;
      if(/people also ask/i.test(txt(n.querySelector('h2, [role="heading"]')))) continue;
      candidates.push(n);
    }

    for(const node of candidates){
      if(items.length>=maxItems) break;
      let a = node.querySelector('.yuRUbf a[href]') || node.querySelector('a[href] h3')?.closest('a[href]') || node.querySelector('a[href]');
      if(!a) continue;
      let href = abs(a.getAttribute('href')||'');
      if(!isResultLikeUrl(href)) continue;
      if(seen.has(href)) continue;

      let title='';
      const h3 = a.querySelector('h3') || node.querySelector('h3');
      title = txt(h3) || txt(a);
      if(isBadText(title)) continue;

      let summary='';
      const sn = node.querySelector('.VwiC3b') || node.querySelector('.IsZvec') || node.querySelector('[data-sncf] .VwiC3b') || node.querySelector('div[style*="-webkit-line-clamp"], .st');
      summary = txt(sn);
      if(!summary){
        const ps=Array.from(node.querySelectorAll('span,div')).map(txt).filter(t=>t && t.length>30);
        summary = ps[0]||'';
      }

      if(searchQ){
        const q=searchQ.toLowerCase();
        const hay=(title+' '+summary).toLowerCase();
        if(hay && hay.indexOf(q)===-1 && q.length>=2) {
          // keep anyway; SERP snippets may not contain full query
        }
      }

      items.push({url:href,title:title||'',summary:summary||''});
      seen.add(href);
    }

    return items;
  }

  function findNextCursor(){
    const scope=document.querySelector('#foot')||document.querySelector('#botstuff')||document.body;
    const links=Array.from(scope.querySelectorAll('a[href]'));
    let best='';
    for(const a of links){
      const t=txt(a).toLowerCase();
      const href=abs(a.getAttribute('href')||'');
      if(!href) continue;
      if(/\bnext\b|下一页|下页|更多结果|more results/.test(t) || a.getAttribute('aria-label') && /next/i.test(a.getAttribute('aria-label'))){
        if(/\/search\?/.test(href) || /[?&]start=\d+/.test(href)) { best=href; break; }
        best=href;
      }
    }
    return best||null;
  }

  function ensureFields(items){
    return items.map(it=>({
      url: String((it&&it.url)||''),
      title: String((it&&it.title)||''),
      summary: String((it&&it.summary)||'')
    }));
  }

  function requireFieldsOk(items){
    const req=(config&&config.requireFields)||['url','title','summary'];
    if(!Array.isArray(req) || !req.length) return items;
    return items.filter(it=>req.every(k=>typeof it[k]==='string'));
  }

  const scope=getScope();
  let items=extractFromContainer(scope,1);
  if(items.length<Math.min(minItems,5)){
    items=extractFromContainer(scope,2);
  }

  items=pickItems(items);
  items=ensureFields(items);
  items=requireFieldsOk(items);
  items=applyFilterSort(items);
  if(items.length>maxItems) items=items.slice(0,maxItems);

  const nextCursor=findNextCursor();
  return {action:'list',items:items,nextCursor:nextCursor,pageUrl:pageUrl};
}
